36→      eventSelectContent({
37→        content_type: 'cta',
38→        content_id: sanitizeTaxonomy(category),
39→        location_1: 'monetizacao',
40→        location_2: 'hub_recompensas_spmais',
41→        location_3: 'saiba_mais',
42→      });
43→
