57→    [
58→      data,
59→      navigation,
60→      parameterPointsProgramActions,
61→    ],
62→  );
63→
64→  return (
65→    <LearnMorePointsSectionView
66→      data={data}
67→      isLoading={status === ParameterPointsProgramStatus.LOADING}
68→      isError={status === ParameterPointsProgramStatus.ERROR}
69→      onPress={handlePress}
